iqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:29:{i:0;s:3:\"hit\";i:1;s:8:\"sezon_id\";i:2;s:5:\"title\";i:3;s:12:\"inside_title\";i:4;s:4:\"slug\";i:5;s:4:\"link\";i:6;s:5:\"link2\";i:7;s:5:\"link3\";i:8;s:6:\"heyzen\";i:9;s:7:\"content\";i:10;s:8:\"location\";i:11;s:5:\"video\";i:12;s:3:\"ses\";i:13;s:7:\"spotify\";i:14;s:5:\"image\";i:15;s:4:\"icon\";i:16;s:4:\"file\";i:17;s:7:\"is_main\";i:18;s:8:\"blade_id\";i:19;s:11:\"category_id\";i:20;s:14:\"translation_of\";i:21;s:11:\"parent_page\";i:22;s:7:\"lang_id\";i:23;s:11:\"form_active\";i:24;s:9:\"published\";i:25;s:13:\"show_homepage\";i:26;s:11:\"show_footer\";i:27;s:15:\"show_sponsorluk\";i:28;s:9:\"show_menu\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}s:16:\"\0*\0forceDeleting\";b:0;}i:88;O:15:\"App\\Models\\Page\":34:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"pages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:34:{s:2:\"id\";i:163;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:33:\"About the Orange Blossom Carnival\";s:12:\"inside_title\";N;s:4:\"slug\";s:33:\"about-the-orange-blossom-carnival\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:1655:\"<p>Adana is one of the most beautiful cities in April…</p>\r\n\r\n<p>Every street is filled with the sweet scent of orange blossoms...</p>\r\n\r\n<p>The scent of orange blossoms is enchanting...</p>\r\n\r\n<p>It cleanses your soul,</p>\r\n\r\n<p>You feel rejuvenated,</p>\r\n\r\n<p>You feel purified…</p>\r\n\r\n<p>For instance, it can make a person forgive even their most estranged old friend, and it’s a bit dangerous too; it can make a person fall in love with the very first person they see on the street.</p>\r\n\r\n<p>April is the most beautiful season in Adana…&nbsp;<strong>Orange Blossom&nbsp;&nbsp;</strong>season… The climate transforms into something incredibly beautiful. Neither cold nor hot… The air feels just like “lemonade.”</p>\r\n\r\n<p>You put on your short-sleeved shirts and head out into the street. As you walk the same streets as Adana’s warm, friendly people, that magnificent scent of orange blossoms, carried by the wind now and then, never leaves your side for 24 hours a day. It leaves you spellbound…</p>\r\n\r\n<p>No matter where in Turkey or the world they live, Adanalıs always come to Adana during the orange blossom season. To not miss out on this excitement, which lasts only once a year for at most 3–4 weeks…</p>\r\n\r\n<p>The orange blossom season generally lasts throughout April, though it may vary by a few days depending on the weather. This site was created to promote this incredible experience so that everyone can enjoy it.</p>\r\n\r\n<p>Please mark your calendars now for next April. We especially invite you all to Adana to experience this unforgettable moment during April, when the orange blossoms are at their peak.</p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";s:43:\"portakal-cicegi-karnavali-hakkinda-pjec.png\";s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:1;s:11:\"category_id\";i:7;s:14:\"translation_of\";i:1;s:11:\"parent_page\";N;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-06 08:05:02\";s:10:\"updated_at\";s:19:\"2026-04-06 08:05:03\";s:10:\"deleted_at\";N;}s:11:\"\0*\0original\";a:34:{s:2:\"id\";i:163;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:33:\"About the Orange Blossom Carnival\";s:12:\"inside_title\";N;s:4:\"slug\";s:33:\"about-the-orange-blossom-carnival\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:1655:\"<p>Adana is one of the most beautiful cities in April…</p>\r\n\r\n<p>Every street is filled with the sweet scent of orange blossoms...</p>\r\n\r\n<p>The scent of orange blossoms is enchanting...</p>\r\n\r\n<p>It cleanses your soul,</p>\r\n\r\n<p>You feel rejuvenated,</p>\r\n\r\n<p>You feel purified…</p>\r\n\r\n<p>For instance, it can make a person forgive even their most estranged old friend, and it’s a bit dangerous too; it can make a person fall in love with the very first person they see on the street.</p>\r\n\r\n<p>April is the most beautiful season in Adana…&nbsp;<strong>Orange Blossom&nbsp;&nbsp;</strong>season… The climate transforms into something incredibly beautiful. Neither cold nor hot… The air feels just like “lemonade.”</p>\r\n\r\n<p>You put on your short-sleeved shirts and head out into the street. As you walk the same streets as Adana’s warm, friendly people, that magnificent scent of orange blossoms, carried by the wind now and then, never leaves your side for 24 hours a day. It leaves you spellbound…</p>\r\n\r\n<p>No matter where in Turkey or the world they live, Adanalıs always come to Adana during the orange blossom season. To not miss out on this excitement, which lasts only once a year for at most 3–4 weeks…</p>\r\n\r\n<p>The orange blossom season generally lasts throughout April, though it may vary by a few days depending on the weather. This site was created to promote this incredible experience so that everyone can enjoy it.</p>\r\n\r\n<p>Please mark your calendars now for next April. We especially invite you all to Adana to experience this unforgettable moment during April, when the orange blossoms are at their peak.</p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";s:43:\"portakal-cicegi-karnavali-hakkinda-pjec.png\";s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:1;s:11:\"category_id\";i:7;s:14:\"translation_of\";i:1;s:11:\"parent_page\";N;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-06 08:05:02\";s:10:\"updated_at\";s:19:\"2026-04-06 08:05:03\";s:10:\"deleted_at\";N;}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:1:{s:10:\"deleted_at\";s:8:\"datetime\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:27:\"\0*\0relationAutoloadCallback\";N;s:26:\"\0*\0relationAutoloadContext\";N;s:10:\"timestamps\";b:1;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:29:{i:0;s:3:\"hit\";i:1;s:8:\"sezon_id\";i:2;s:5:\"title\";i:3;s:12:\"inside_title\";i:4;s:4:\"slug\";i:5;s:4:\"link\";i:6;s:5:\"link2\";i:7;s:5:\"link3\";i:8;s:6:\"heyzen\";i:9;s:7:\"content\";i:10;s:8:\"location\";i:11;s:5:\"video\";i:12;s:3:\"ses\";i:13;s:7:\"spotify\";i:14;s:5:\"image\";i:15;s:4:\"icon\";i:16;s:4:\"file\";i:17;s:7:\"is_main\";i:18;s:8:\"blade_id\";i:19;s:11:\"category_id\";i:20;s:14:\"translation_of\";i:21;s:11:\"parent_page\";i:22;s:7:\"lang_id\";i:23;s:11:\"form_active\";i:24;s:9:\"published\";i:25;s:13:\"show_homepage\";i:26;s:11:\"show_footer\";i:27;s:15:\"show_sponsorluk\";i:28;s:9:\"show_menu\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}s:16:\"\0*\0forceDeleting\";b:0;}i:89;O:15:\"App\\Models\\Page\":34:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"pages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:34:{s:2:\"id\";i:164;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:26:\"Who is Ali Haydar Bozkurt?\";s:12:\"inside_title\";N;s:4:\"slug\";s:25:\"who-is-ali-haydar-bozkurt\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:4882:\"<p>I was born in 1967. I spent the first 29 years of my life in Adana, where the streets smell of orange blossoms in April.</p>\r\n\r\n<p>During this time, alongside my education, I worked professionally in theater. I also played licensed basketball for many years. I devoted a considerable amount of time to hobbies such as photography, music, etc.</p>\r\n\r\n<p>I continue to visit Adana regularly at certain intervals.</p>\r\n\r\n<p>However, especially every April — or as we, the lovers of Adana, call it, the Orange Blossom Season — no matter where I am in the world, I always make sure to come to Adana. There was only one year I couldn’t do this. That year, thankfully, my teacher and dear friends collected orange blossoms, placed them in jars, and sent them to me by cargo. I kept those jars in my refrigerator for a week. Every morning and evening, I would open the jars, smell them, close my eyes, and imagine myself walking through the streets of Adana in April. It may be a bit difficult to explain this to someone who has never experienced it before. But for those who have, it is a beauty that stays with them for a lifetime.</p>\r\n\r\n<p>Every April, I go to Adana and, especially in the late afternoon hours when the scent of orange blossoms is at its peak, I put on my jeans, my t-shirt, and my indispensable white Converse, and head out to the city streets. These walks are something I never get tired of or bored with… Every place I pass holds a different memory... In the background, waves of that magnificent orange blossom scent… That magical fragrance that cleanses my soul enough to make me love everyone and everything…</p>\r\n\r\n<p>When we were children, there were orange groves very close to the city center in Adana, and in the evenings, the wind would carry the scent of orange blossoms from those groves into the streets of the city. It would hit our faces in waves wherever it passed… Now, the orange groves in the city center may no longer exist, but thanks to the orange (bitter orange) trees on every street and the trees in the parks in the city center, you can still find the same scent on every street you walk.</p>\r\n\r\n<p><strong>I had a socially, artistically, and sports-oriented educational life in Adana. I am a graduate of Ayas College. In fact, I am one of the first male graduates of the school. There were only 2 male students in our class. Our only problem was that we had to form mixed teams with girls because we couldn’t form a boys’ basketball team for inter-class matches. We were lucky… We had memories to tell for a lifetime and friendships that would last forever.</strong></p>\r\n\r\n<p>I never left Adana during my university years and graduated from Çukurova University, Department of Business Administration (English).</p>\r\n\r\n<p>Throughout my entire education life, I never studied lessons. My time outside of classes was so full with activities like theater, basketball, music, and photography that I had no time to study, so I tried to learn by listening carefully during lessons. Despite this, I believe I was a successful student.</p>\r\n\r\n<p>In 1996 (I was 29 years old at the time), although somewhat late, I moved to Istanbul to start my professional career.</p>\r\n\r\n<p>During this time, I held various positions in different companies. I am currently serving as the CEO of Toyota Turkey. At the same time, I also serve as the CEO of ALJ Mobility Europe and Turkey.</p>\r\n\r\n<p>I believe that success comes from “making a difference” and that the most fundamental element for achieving all goodness and beauty in the world is effective communication.</p>\r\n\r\n<p>For all these reasons, I wanted to share with you the unique and distinctive beauties of Adana. The main purpose of establishing this website is to introduce Adana’s lesser-known orange blossom season and its beauties to as many people as possible.</p>\r\n\r\n<p>With this in mind, we set out with the slogan “In Adana in April!”. With the support of all friends, whether from Adana or not, we aim to grow this movement and ensure that more people visit Adana every April to experience this incredible atmosphere.</p>\r\n\r\n<p>This invitation has no political or commercial purpose whatsoever. By preserving our sensitivity on this matter, we simply want to create something out of “love” and invite everyone who wishes to experience this beauty with us in Adana in April.</p>\r\n\r\n<p>Although the orange blossom season may vary by a few days each year depending on the climate, it generally falls between April 5–20. For this reason, we invite you to join us during the first week of April, when the scent of orange blossoms is at its most intense. Of course, I would also recommend that you do not plan just a one-day visit. In the relevant section of this website, I will try to provide you with detailed information on “What to Do in Adana”.</p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";s:29:\"ali-haydar-bozkurt-kimdir.png\";s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:1;s:11:\"category_id\";i:7;s:14:\"translation_of\";i:2;s:11:\"parent_page\";N;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-06 08:15:24\";s:10:\"updated_at\";s:19:\"2026-04-06 08:15:24\";s:10:\"deleted_at\";N;}s:11:\"\0*\0original\";a:34:{s:2:\"id\";i:164;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:26:\"Who is Ali Haydar Bozkurt?\";s:12:\"inside_title\";N;s:4:\"slug\";s:25:\"who-is-ali-haydar-bozkurt\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:4882:\"<p>I was born in 1967. I spent the first 29 years of my life in Adana, where the streets smell of orange blossoms in April.</p>\r\n\r\n<p>During this time, alongside my education, I worked professionally in theater. I also played licensed basketball for many years. I devoted a considerable amount of time to hobbies such as photography, music, etc.</p>\r\n\r\n<p>I continue to visit Adana regularly at certain intervals.</p>\r\n\r\n<p>However, especially every April — or as we, the lovers of Adana, call it, the Orange Blossom Season — no matter where I am in the world, I always make sure to come to Adana. There was only one year I couldn’t do this. That year, thankfully, my teacher and dear friends collected orange blossoms, placed them in jars, and sent them to me by cargo. I kept those jars in my refrigerator for a week. Every morning and evening, I would open the jars, smell them, close my eyes, and imagine myself walking through the streets of Adana in April. It may be a bit difficult to explain this to someone who has never experienced it before. But for those who have, it is a beauty that stays with them for a lifetime.</p>\r\n\r\n<p>Every April, I go to Adana and, especially in the late afternoon hours when the scent of orange blossoms is at its peak, I put on my jeans, my t-shirt, and my indispensable white Converse, and head out to the city streets. These walks are something I never get tired of or bored with… Every place I pass holds a different memory... In the background, waves of that magnificent orange blossom scent… That magical fragrance that cleanses my soul enough to make me love everyone and everything…</p>\r\n\r\n<p>When we were children, there were orange groves very close to the city center in Adana, and in the evenings, the wind would carry the scent of orange blossoms from those groves into the streets of the city. It would hit our faces in waves wherever it passed… Now, the orange groves in the city center may no longer exist, but thanks to the orange (bitter orange) trees on every street and the trees in the parks in the city center, you can still find the same scent on every street you walk.</p>\r\n\r\n<p><strong>I had a socially, artistically, and sports-oriented educational life in Adana. I am a graduate of Ayas College. In fact, I am one of the first male graduates of the school. There were only 2 male students in our class. Our only problem was that we had to form mixed teams with girls because we couldn’t form a boys’ basketball team for inter-class matches. We were lucky… We had memories to tell for a lifetime and friendships that would last forever.</strong></p>\r\n\r\n<p>I never left Adana during my university years and graduated from Çukurova University, Department of Business Administration (English).</p>\r\n\r\n<p>Throughout my entire education life, I never studied lessons. My time outside of classes was so full with activities like theater, basketball, music, and photography that I had no time to study, so I tried to learn by listening carefully during lessons. Despite this, I believe I was a successful student.</p>\r\n\r\n<p>In 1996 (I was 29 years old at the time), although somewhat late, I moved to Istanbul to start my professional career.</p>\r\n\r\n<p>During this time, I held various positions in different companies. I am currently serving as the CEO of Toyota Turkey. At the same time, I also serve as the CEO of ALJ Mobility Europe and Turkey.</p>\r\n\r\n<p>I believe that success comes from “making a difference” and that the most fundamental element for achieving all goodness and beauty in the world is effective communication.</p>\r\n\r\n<p>For all these reasons, I wanted to share with you the unique and distinctive beauties of Adana. The main purpose of establishing this website is to introduce Adana’s lesser-known orange blossom season and its beauties to as many people as possible.</p>\r\n\r\n<p>With this in mind, we set out with the slogan “In Adana in April!”. With the support of all friends, whether from Adana or not, we aim to grow this movement and ensure that more people visit Adana every April to experience this incredible atmosphere.</p>\r\n\r\n<p>This invitation has no political or commercial purpose whatsoever. By preserving our sensitivity on this matter, we simply want to create something out of “love” and invite everyone who wishes to experience this beauty with us in Adana in April.</p>\r\n\r\n<p>Although the orange blossom season may vary by a few days each year depending on the climate, it generally falls between April 5–20. For this reason, we invite you to join us during the first week of April, when the scent of orange blossoms is at its most intense. Of course, I would also recommend that you do not plan just a one-day visit. In the relevant section of this website, I will try to provide you with detailed information on “What to Do in Adana”.</p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";s:29:\"ali-haydar-bozkurt-kimdir.png\";s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:1;s:11:\"category_id\";i:7;s:14:\"translation_of\";i:2;s:11:\"parent_page\";N;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-06 08:15:24\";s:10:\"updated_at\";s:19:\"2026-04-06 08:15:24\";s:10:\"deleted_at\";N;}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:1:{s:10:\"deleted_at\";s:8:\"datetime\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s:14:\"\0*\0observables\";a:0:{}s:12:\"\0*\0relations\";a:0:{}s:10:\"\0*\0touches\";a:0:{}s:27:\"\0*\0relationAutoloadCallback\";N;s:26:\"\0*\0relationAutoloadContext\";N;s:10:\"timestamps\";b:1;s:13:\"usesUniqueIds\";b:0;s:9:\"\0*\0hidden\";a:0:{}s:10:\"\0*\0visible\";a:0:{}s:11:\"\0*\0fillable\";a:29:{i:0;s:3:\"hit\";i:1;s:8:\"sezon_id\";i:2;s:5:\"title\";i:3;s:12:\"inside_title\";i:4;s:4:\"slug\";i:5;s:4:\"link\";i:6;s:5:\"link2\";i:7;s:5:\"link3\";i:8;s:6:\"heyzen\";i:9;s:7:\"content\";i:10;s:8:\"location\";i:11;s:5:\"video\";i:12;s:3:\"ses\";i:13;s:7:\"spotify\";i:14;s:5:\"image\";i:15;s:4:\"icon\";i:16;s:4:\"file\";i:17;s:7:\"is_main\";i:18;s:8:\"blade_id\";i:19;s:11:\"category_id\";i:20;s:14:\"translation_of\";i:21;s:11:\"parent_page\";i:22;s:7:\"lang_id\";i:23;s:11:\"form_active\";i:24;s:9:\"published\";i:25;s:13:\"show_homepage\";i:26;s:11:\"show_footer\";i:27;s:15:\"show_sponsorluk\";i:28;s:9:\"show_menu\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}s:16:\"\0*\0forceDeleting\";b:0;}i:90;O:15:\"App\\Models\\Page\":34:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"pages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:34:{s:2:\"id\";i:173;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:13:\"Adana Flavors\";s:12:\"inside_title\";s:13:\"Adana Flavors\";s:4:\"slug\";s:13:\"adana-flavors\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:355:\"<p>Adana, which has become a brand in the field of gastronomy, promotes its culinary culture to the world with its traditional Flavor Festival. Delicious local tastes such as Adana kebab, lahmacun, bici bici dessert, sıkma-ayran, şalgam, şırdan, and yüksük çorbası bring visitors together with a wonderful feast of flavors during the carnival.</p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";N;s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:4;s:11:\"category_id\";i:8;s:14:\"translation_of\";i:96;s:11:\"parent_page\";N;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-07 10:35:16\";s:10:\"updated_at\";s:19:\"2026-04-07 10:35:16\";s:10:\"deleted_at\";N;}s:11:\"\0*\0original\";a:34:{s:2:\"id\";i:173;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:13:\"Adana Flavors\";s:12:\"inside_title\";s:13:\"Adana Flavors\";s:4:\"slug\";s:13:\"adana-flavors\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:355:\"<p>Adana, which has become a brand in the field of gastronomy, promotes its culinary culture to the world with its traditional Flavor Festival. Delicious local tastes such as Adana kebab, lahmacun, bici bici dessert, sıkma-ayran, şalgam, şırdan, and yüksük çorbası bring visitors together with a wonderful feast of flavors during the carnival.</p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";N;s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:4;s:11:\"category_id\";i:8;s:14:\"translation_of\";i:96;s:11:\"parent_page\";N;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-07 10:35:16\";s:10:\"updated_at\";s:19:\"2026-04-07 10:35:16\";s:10:\"deleted_at\";N;}s:10:\"\0*\0changes\";a:0:{}s:11:\"\0*\0previous\";a:0:{}s:8:\"\0*\0casts\";a:1:{s:10:\"deleted_at\";s:8:\"datetime\";}s:17:\"\0*\0classCastCache\";a:0:{}s:21:\"\0*\0attributeCastCache\";a:0:{}s:13:\"\0*\0dateFormat\";N;s:10:\"\0*\0appends\";a:0:{}s:19:\"\0*\0dispatchesEvents\";a:0:{}s: