ation_of\";i:21;s:11:\"parent_page\";i:22;s:7:\"lang_id\";i:23;s:11:\"form_active\";i:24;s:9:\"published\";i:25;s:13:\"show_homepage\";i:26;s:11:\"show_footer\";i:27;s:15:\"show_sponsorluk\";i:28;s:9:\"show_menu\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}s:16:\"\0*\0forceDeleting\";b:0;}i:118;O:15:\"App\\Models\\Page\":34:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"pages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:34:{s:2:\"id\";i:207;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:28:\"Orange Blossom Carnival 2022\";s:12:\"inside_title\";N;s:4:\"slug\";s:28:\"orange-blossom-carnival-2022\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:1102:\"<p><span style=\"background-color:rgb(253, 253, 253); color:rgb(0, 0, 0); font-family:manrope,serif; font-size:medium\">The carnival, in its tenth year, took place between March 23-27, 2022. It is estimated that approximately 300,000 carnival visitors from within Turkey and abroad spent an average of 500 TL per person. Considering accommodation, food and beverages, entertainment, shopping, and similar expenses, the contribution of visitors from outside Adana to the Adana economy is estimated to be around 150 million TL. Furthermore, taking into account the symbolic expenditure of approximately 200 TL per person by the approximately 1 million people from Adana attending the events during the carnival on food, beverages, entertainment, and shopping, it is seen that an internal trade volume of around 200 million TL was generated. When other expenses such as intercity air and land transportation, and intracity private and public transportation are added to all these figures, it has been reported that the Orange Blossom Carnival generated an economy of approximately 350 million TL.</span></p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";s:42:\"2022-yilinda-portakal-cicegi-karnavali.jpg\";s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:1;s:11:\"category_id\";i:7;s:14:\"translation_of\";i:7;s:11:\"parent_page\";i:189;s:7:\"lang_id\";i:2;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-29 10:30:44\";s:10:\"updated_at\";s:19:\"2026-04-29 10:30:44\";s:10:\"deleted_at\";N;}s:11:\"\0*\0original\";a:34:{s:2:\"id\";i:207;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:28:\"Orange Blossom Carnival 2022\";s:12:\"inside_title\";N;s:4:\"slug\";s:28:\"orange-blossom-carnival-2022\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:1102:\"<p><span style=\"background-color:rgb(253, 253, 253); color:rgb(0, 0, 0); font-family:manrope,serif; font-size:medium\">The carnival, in its tenth year, took place between March 23-27, 2022. It is estimated that approximately 300,000 carnival visitors from within Turkey and abroad spent an average of 500 TL per person. Considering accommodation, food and beverages, entertainment, shopping, and similar expenses, the contribution of visitors from outside Adana to the Adana economy is estimated to be around 150 million TL. Furthermore, taking into account the symbolic expenditure of approximately 200 TL per person by the approximately 1 million people from Adana attending the events during the carnival on food, beverages, entertainment, and shopping, it is seen that an internal trade volume of around 200 million TL was generated. When other expenses such as intercity air and land transportation, and intracity private and public transportation are added to all these figures, it has be