rm_active\";i:24;s:9:\"published\";i:25;s:13:\"show_homepage\";i:26;s:11:\"show_footer\";i:27;s:15:\"show_sponsorluk\";i:28;s:9:\"show_menu\";}s:10:\"\0*\0guarded\";a:1:{i:0;s:1:\"*\";}s:16:\"\0*\0forceDeleting\";b:0;}i:166;O:15:\"App\\Models\\Page\":34:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"pages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:34:{s:2:\"id\";i:256;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:55:\"2026 Portakal Çiçeği Karnavalı Geri Bildirim Anketi\";s:12:\"inside_title\";N;s:4:\"slug\";s:51:\"2026-portakal-cicegi-karnavali-geri-bildirim-anketi\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:1200:\"<p>Portakal Çiçeği Karnavalı’nın ekonomik, toplumsal, kültürel ve deneyimsel etkisini bütüncül bir şekilde değerlendirmek amacıyla bu çalışma yürütülmektedir. Elde edilecek veriler; karnavalın şehir üzerindeki etkisini daha net ortaya koymak, katılımcı deneyimini anlamak ve gelecek yıllarda daha güçlü, daha sürdürülebilir ve daha etkili bir organizasyon kurgulamak için kullanılacaktır.</p>\r\n\r\n<p>Çalışma kapsamında anketler, saha gözlemleri ve dijital veri analizleri birlikte değerlendirilerek kapsamlı bir etki analizi oluşturulmaktadır. Bu yaklaşım sayesinde yalnızca katılım ve memnuniyet değil, aynı zamanda davranışlar, harcama eğilimleri ve sürdürülebilirlik etkileri de analiz edilmektedir.</p>\r\n\r\n<p>Tüm veriler anonim olarak toplanmakta olup yalnızca etki analizi ve geliştirme amaçlı kullanılacaktır. Katkı sağlayan tüm katılımcılara teşekkür ederiz.</p>\r\n\r\n<p><a href=\"https://forms.gle/JcBbu9jCiSLbuKok6\" style=\"font-size: 20px; line-height: 20px; color: rgb(226, 131, 55); padding: 5px 0px; border-radius: 34px; margin-top: 20px; font-weight: 600;\" target=\"_blank\">Ankete ulaşmak için tıklayınız.</a></p>\";s:8:\"location\";N;s:5:\"video\";N;s:15:\"youtubeplaylist\";N;s:3:\"ses\";N;s:7:\"spotify\";N;s:5:\"image\";s:60:\"2026-portakal-cicegi-karnavali-geri-bildirim-anketi-p4vo.jpg\";s:4:\"icon\";N;s:4:\"file\";N;s:7:\"is_main\";i:0;s:8:\"blade_id\";i:33;s:11:\"category_id\";i:2;s:14:\"translation_of\";N;s:11:\"parent_page\";i:147;s:7:\"lang_id\";i:1;s:11:\"form_active\";i:0;s:9:\"published\";i:1;s:9:\"show_menu\";i:0;s:13:\"show_homepage\";i:0;s:11:\"show_footer\";i:0;s:15:\"show_sponsorluk\";i:0;s:10:\"created_at\";s:19:\"2026-04-30 13:10:12\";s:10:\"updated_at\";s:19:\"2026-04-30 13:10:33\";s:10:\"deleted_at\";N;}s:11:\"\0*\0original\";a:34:{s:2:\"id\";i:256;s:3:\"hit\";N;s:8:\"sezon_id\";N;s:5:\"title\";s:55:\"2026 Portakal Çiçeği Karnavalı Geri Bildirim Anketi\";s:12:\"inside_title\";N;s:4:\"slug\";s:51:\"2026-portakal-cicegi-karnavali-geri-bildirim-anketi\";s:4:\"link\";N;s:5:\"link2\";N;s:5:\"link3\";N;s:6:\"heyzen\";N;s:7:\"content\";s:1200:\"<p>Portakal Çiçeği Karnavalı’nın ekonomik, toplumsal, kültürel ve deneyimsel etkisini bütüncül bir şekilde değerlendirmek amacıyla bu çalışma yürütülmektedir. Elde edilecek veriler; karnavalın şehir üzerindeki etkisini daha net ortaya koymak, katılımcı deneyimini anlamak ve gelecek yıllarda daha güçlü, daha sürdürülebilir ve daha etkili bir organizasyon kurgulamak için kullanılacaktır.</p>\r\n\r\n<p>Çalışma kapsamında anketler, saha gözlemleri ve dijital veri analizleri birlikte değerlendirilerek kapsamlı bir etki analizi oluşturulmaktadır. Bu yaklaşım sayesinde yalnızca katılım ve memnuniyet değil, aynı zamanda davranışlar, harcama eğilimleri ve sürdürülebilirlik etkileri de analiz edilmektedir.</p>\r\n\r\n<p>Tüm veriler anonim olarak toplanmakta olup yalnızca etki analizi ve geliştirme amaçlı kullanılacaktır. Katkı sağlayan tüm katılımcılara teşekkür ederiz.</p>\r\n\r\n<p><a href=\"https://forms.gle/JcBbu9jC