INSERT INTO `comments` (`id`, `name`, `content`, `image`, `hit`, `published`, `lang_id`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'Ali Haydar Bozkurt', 'Mesela en küskün olduğu eski dostu affettirebilir insana tehlikelidir de biraz; insanı, yolda gördüğü ilk kişiye aşık edebilir.', NULL, 10, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:14', NULL),
(2, 'Hadise', 'Japonya’nın Sakurası, Adana’nın da Portakal Çiçeği var. Sırf bu çiçeği görmek ve koklamak için her yıl milyonlarca insan Adana’ya akın ediyor. E hadi o zaman, bu yıl da Türkiye’de nisan ayında düzenlenen Adana Portakal Çiçeği Karnavalı sizi bekliyor.', NULL, 20, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:14', NULL),
(3, 'Timur Savcı', 'Ben Adana’da doğdum, Adana’da büyüdüm. Üniversite yıllarında İstanbul’a geldim. Beni çok duygulandırıyor. Portakal Çiçeği Karnavalı deyince, bence Türkiye’nin ilk karnavalını biz Adanalılar olarak yaptığımız için mutluluk ve her zaman gurur duyuyoruz.', NULL, 30, 0, 1, '2026-04-10 13:09:00', '2026-04-10 13:14:18', '2025-02-17 10:15:25'),
(4, 'Caner Cindoruk', 'Ben nisan ayında Adana’da doğmuşum. O yüzden nisan ayı benim için çok kıymetli. Çocukluğuma dair portakal çiçeğinin tüm Adana’da kokuyor olması, insanın burnunun direğini sızlatıyor olması... Hâlâ o kokuyu duyumsarım. O yüzden benim için çok özel. Sanırım nisan en çok Adana’ya yakışıyor.', NULL, 40, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:15', NULL),
(5, 'Zuhal Olcay', 'Portakal Çiçeği tabii ki olağanüstü bir festival. Artık orası bir gelenek. Bütün dostların, güzelliklerin bir arada yaşandığı çok hoş bir etkinlik. Ve tabii ki portakal çiçekleri çok güzel kokar, biliyorsunuz.', NULL, 50, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:15', NULL),
(6, 'Timur Savcı', 'Ben Adana’da doğdum, Adana’da büyüdüm. Üniversite yıllarında İstanbul’a geldim. Beni çok duygulandırıyor. Portakal Çiçeği Karnavalı deyince, bence Türkiye’nin ilk karnavalını biz Adanalılar olarak yaptığımız için mutluluk ve her zaman gurur duyuyoruz.', NULL, 60, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:17', NULL),
(7, 'Melis Sezen', 'Adana çok mutlu bir şehir. İnsanlarıyla da birlikte enerjik olduğu gibi, kendini yansıtmaktan hiçbir zaman çekinmeyen bir şehir. O yüzden ben kendimi Adana\'ya çok sıcak hissediyorum. O Adana\'nın sıcağını da çok seviyorum. Ve Portakal Çiçeği Karnavalı, ülkemizdeki tek karnaval. O yüzden böyle bir karnavalımız olduğu için de çok mutluyum. Heyecanla bekliyoruz.', NULL, 70, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:17', NULL),
(8, 'Jess Molho', 'Benim için Adana yazın sıcak demek, nem demek, her daim kebap demek. Ama karnavalla tanıştıktan sonra da artık birincil olarak karnaval demek. Karnavalı sunmuştum pandemi sırasında, ilk karnaval deneyimimdi. Çok beğenmiştim. Bu sene tekrar orada olacağım, onun için çok mutluyum. Dünyanın her yerinden insanların gelmesi beni özellikle Adana’ya şaşırtmıştı. Japonlar, Çinliler, farklı milletlerden insanların Adana’yı duyması ve festivale iştirak etmesi beni çok etkilemişti.', NULL, 80, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:19', NULL),
(9, 'Salih Bademci', 'Adana bir kere benim için çok özel bir yer. Çünkü ben festivallerde ve tiyatrolarda Adana\'ya çok gittim. Portakal Çiçeği Festivaline hiç katılamadım, yalan söylemeyeceğim. Ama Adana, beni özellikle seyircisiyle çok şaşırtmış bir şehirdir. Oynadığım en keyifli oyunları Adana\'ya gittiğim turnelerde ve tiyatro festivallerinde oynadım. Aynı zamanda zaten mutfağını falan hiç konuşmuyorum. Ama benim için kültürel olarak çok zengin ve duyarlı bir şehir olduğunu düşünüyorum.', NULL, 90, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:19', NULL),
(10, 'Emre Karayel', 'Benim memleketim Adana, çocukluğum demek. Portakal çiçeği kokusu, hepimizin içinde büyüdüğü bir koku. O yüzden çok özel. Bir de bunun festival değil, karnaval olması ve Adana’ya ait özel bir etkinlik olması, Türkiye’de tek karnaval olması apayrı bir keyif. Benim adıma büyük bir gurur kaynağı. Başladığı ilk günden beri de elimden gelen her türlü desteği verdim karnavalımıza, yolu açık olsun.', NULL, 100, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:20', NULL),
(12, 'Levent Özdilek', 'Hmmm... Her yer portakal çiçeği kokuyor, bir kere bu büyülü bir şey. Zaten az önce yine Ali Haydar’la konuşuyorduk. “Portakal çiçeği kokuyorsun.” dedim. “Yok.” dedi, “Masalarda var, her yere getirdim.” dedi. “Yok.” dedim, “Ben senden kokluyorum, onun ruhu var hepimizde.” Çok önemli. Adana diyince aklıma neler geliyor neler, anlatamam burada. Söyleyemem. Çocukluğumuz yani, bütün hayatımız. Adana dedi mi biz Adanalılar için bütün sular durur. Her şeyimizi bırakırız ve Adana’ya gideriz.', NULL, 110, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:21', NULL),
(13, 'Celil Nalçakan', 'Vallahi ben fahri bir Adanalı olarak heyecanla bekliyorum. İnşallah şahane olacak, inşallah ben de iştirak ederim, böyle bir vakit olur da. Adana ile ilgili konuşalım mesela; şu an o kadar açım ki içeri girip kebap, kıyma yemek istiyorum. Çok seviyorum, hakikaten. Üniversitedeyken ev arkadaşım Adanalıydı. Sivas’ta okudum. Hafta sonları falan, o zaten memleketini özlüyordu, ben de hakikaten çok seviyordum Adana’yı. Hafta sonları kaçıp kaçıp gidiyorduk. İnşallah bu sefer de kaçmadan gideceğiz.', NULL, 120, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:24', NULL),
(14, 'Menderes Samancılar', 'Adana deyince aklımıza sanatçılar geliyor. Orhan Kemal, Yaşar Kemal, Yılmaz Güney, Muzaffer İzgü diye devam eder gideriz. Ama Adana deyince önce karnaval diyoruz biz. Portakal Çiçeği Karnavalı ruhumuzu ve ülkemizi yeşertecektir yeniden. Sevgi, barış ve kardeşlik... Bundan hiçbir şekilde ödün vermeyeceğiz.', NULL, 130, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:24', NULL),
(15, 'Saner Ayar', 'Benim için nevi şahsına münhasır insanların yaşadığı muazzam bir şehir. Tabii Adana’yı mutfağı ile tanıyoruz, mutfağı ile biliyoruz ama Adana’nın yetiştirdiği insanlar muazzam. Bir de bu gece öğrendim; ben Adana’ya gittiğimde o kokuyu alıyordum ama adını koyamamıştım. Bu Portakal Çiçeği Karnavalı olduğu dönemde Adana, aslında portakal çiçeği kokuyor. Bütün şehir üzerine parfüm sıkılmış gibi. Adını koyamadığım bir şeydi. Adana, Türkiye’nin bütün renklerinin oluştuğu bir şehir ve çok önemli. Yaşasın Adana! Tüm Adanalıları bir araya getiren, bütün Türkiye’yi oraya taşıyan, dünyanın dikkatini çeken, organizasyonu yapan herkesin ellerine sağlık.', NULL, 140, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:25', NULL),
(16, 'Nebil Özgentürk', 'Adana deyince dünyaya nam salmış çok değerli sanat insanları geliyor aklıma. Ve Adana deyince tabii ki nisan ayında festival, Adana Festivali geliyor. Portakal Çiçeği Festivali geliyor. Ali Haydar kardeşimin fikir önderi olduğu bu festivalin ilk günlerinden beri içindeyim. Nasıl ki benim Adana çocukluğumsa, bir yandan da nisan ayında Adana Festivali, elimde doğmuş bir çocuk gibi.', NULL, 150, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:26', NULL),
(17, 'Aslı Orcan', 'Benim Adana deyince ilk aklıma Portakal Çiçeği Karnavalı geliyor. Çünkü ilk Adana’ya bu sebeple gitmiştim. Adana şehrini böyle tanıdım, karnaval sayesinde tanıdım. O yüzden Adana deyince aklıma karnaval geliyor. Bence bütün halkın hep birlikte eğlenmesi, aynı ruhta olması ve o ruhu birlikte yaşama sevinci çok kıymetli. Tam bir karnaval coşkusu oluyor, bence bu çok güzel bir şey.', NULL, 160, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:27', NULL),
(18, 'Karnavaldan Mesaj', 'Portakal çiçekleri arasında yaşanan büyü sona erdi... Adana sokaklarında dans eden renkler, kalplere dokunan melodiler, unutulmaz anılar... 2025 karnavalının perdesi kapandı. Ama merak etmeyin, 2026\'da daha da muhteşem sürprizlerle buluşuyoruz!', NULL, 170, 1, 1, '2026-04-10 13:09:00', '2026-04-10 13:49:28', NULL),
(19, 'Ali Haydar Bozkurt', 'For instance, it can make someone forgive their most resentful old friend; it is also a bit dangerous; it can make one fall in love with the first person they see on the road.', NULL, 10, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:14', NULL),
(20, 'Hadise', 'Japan has its Sakura, and Adana has its Orange Blossom. Millions of people flock to Adana every year just to see and smell this flower. Well then, the Adana Orange Blossom Carnival, held in Turkey in April, is waiting for you this year.', NULL, 20, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:14', NULL),
(21, 'Timur Savcı', 'I was born and raised in Adana. I came to Istanbul during my university years. It makes me very emotional. When it comes to the Orange Blossom Carnival, I think we, as people of Adana, are happy and always proud to have created Turkey\'s first carnival.', NULL, 30, 0, 2, '2026-04-10 10:09:00', '2026-04-10 10:14:18', '2025-02-17 07:15:25'),
(22, 'Caner Cindoruk', 'I was born in Adana in April. That\'s why April is very precious to me. The fact that the orange blossom smells all over Adana, reminding me of my childhood, makes one feel a deep ache of nostalgia... I still sense that scent. That\'s why it’s very special to me. I think April suits Adana the most.', NULL, 40, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:15', NULL),
(23, 'Zuhal Olcay', 'Orange Blossom is, of course, an extraordinary festival. It is now a tradition. A very pleasant event where all friends and beauties are experienced together. And of course, orange blossoms smell wonderful, you know.', NULL, 50, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:15', NULL),
(24, 'Timur Savcı', 'I was born and raised in Adana. I came to Istanbul during my university years. It makes me very emotional. When it comes to the Orange Blossom Carnival, I think we, as people of Adana, are happy and always proud to have created Turkey\'s first carnival.', NULL, 60, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:17', NULL),
(25, 'Melis Sezen', 'Adana is a very happy city. Just as it is energetic with its people, it is a city that never hesitates to reflect itself. That\'s why I feel very warm towards Adana. I also love that heat of Adana. And the Orange Blossom Carnival is the only carnival in our country. Therefore, I am very happy that we have such a carnival. We are waiting with excitement.', NULL, 70, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:17', NULL),
(26, 'Jess Molho', 'For me, Adana means heat in summer, it means humidity, it always means kebab. But after meeting the carnival, it now primarily means the carnival. I hosted the carnival during the pandemic; it was my first carnival experience. I liked it very much. I will be there again this year, and I am very happy about it. I was particularly surprised that people from all over the world came to Adana. It impressed me a lot that Japanese, Chinese, and people of different nations heard about Adana and participated in the festival.', NULL, 80, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:19', NULL),
(27, 'Salih Bademci', 'Adana is a very special place for me. Because I have been to Adana many times for festivals and theaters. I have never been able to attend the Orange Blossom Festival, I won’t lie. But Adana is a city that has surprised me, especially with its audience. I performed the most enjoyable plays during the tours and theater festivals I went to in Adana. At the same time, I’m not even mentioning the cuisine. But I think it is a culturally very rich and sensitive city.', NULL, 90, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:19', NULL),
(28, 'Emre Karayel', 'My hometown Adana means my childhood. The scent of orange blossoms is a scent we all grew up with. That\'s why it\'s so special. Also, the fact that this is not a festival but a carnival, and it\'s a special event unique to Adana, being the only carnival in Turkey, is a distinct pleasure. It is a great source of pride for me. I have given all kinds of support I can to our carnival since the first day it started; may its path be clear.', NULL, 100, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:20', NULL),
(29, 'Levent Özdilek', 'Hmmm... Everywhere smells of orange blossoms; first of all, this is something magical. I was just talking to Ali Haydar a moment ago. I said, “You smell like orange blossoms.” He said, “No, it\'s on the tables, I brought it everywhere.” I said, “No, I smell it from you; its spirit is in all of us.” It’s very important. I can’t explain here what comes to my mind when I think of Adana. I can’t say. It’s our childhood, our whole life. When Adana is mentioned, everything else stops for us Adanians. We leave everything and go to Adana.', NULL, 110, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:21', NULL),
(30, 'Celil Nalçakan', 'Well, as an honorary Adanian, I am waiting with excitement. I hope it will be wonderful, and I hope I can participate if there is time. Let\'s talk about Adana, for example; I am so hungry right now that I want to go in and eat kebab and minced meat. I really love it. When I was at university, my roommate was from Adana. I studied in Sivas. On weekends, he was already homesick, and I really loved Adana. We used to run away there on weekends. I hope this time we will go without having to run away.', NULL, 120, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:24', NULL),
(31, 'Menderes Samancılar', 'When we think of Adana, artists come to mind. We can go on with Orhan Kemal, Yaşar Kemal, Yılmaz Güney, Muzaffer İzgü. But when we say Adana, first we say carnival. The Orange Blossom Carnival will revive our spirits and our country. Love, peace, and brotherhood... We will never compromise on this.', NULL, 130, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:24', NULL),
(32, 'Saner Ayar', 'For me, it is a magnificent city where unique people live. Of course, we know Adana for its cuisine, but the people Adana has raised are magnificent. Also, I learned tonight; I used to get that scent when I went to Adana, but I couldn’t name it. During the Orange Blossom Carnival, Adana actually smells like orange blossoms. It’s like the whole city has been sprayed with perfume. It was something I couldn’t name. Adana is a city where all the colors of Turkey come together, and it’s very important. Long live Adana! Health to the hands of everyone who organizes this, bringing all Adanians together and carrying all of Turkey there, attracting the world’s attention.', NULL, 140, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:25', NULL),
(33, 'Nebil Özgentürk', 'When I think of Adana, very valuable artists who have made a name for themselves in the world come to mind. And of course, when I think of Adana in April, the festival, the Adana Festival comes to mind. The Orange Blossom Festival comes to mind. I have been involved in this festival, of which my brother Ali Haydar was the thought leader, since its first days. Just as Adana is my childhood, the Adana Festival in April is like a child born into my hands.', NULL, 150, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:26', NULL),
(34, 'Aslı Orcan', 'The first thing that comes to my mind when I think of Adana is the Orange Blossom Carnival. Because I went to Adana for the first time for this reason. I got to know the city of Adana this way, thanks to the carnival. That\'s why the carnival comes to mind when I think of Adana. I think it is very precious for all people to have fun together, to be in the same spirit, and to have the joy of living that spirit together. It’s a total carnival enthusiasm, I think it\'s a very beautiful thing.', NULL, 160, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:27', NULL),
(35, 'Karnavaldan Mesaj', 'The magic experienced among the orange blossoms has come to an end... Colors dancing in the streets of Adana, melodies touching hearts, unforgettable memories... The curtain on the 2025 carnival has closed. But don\'t worry, we are meeting in 2026 with even more magnificent surprises!', NULL, 170, 1, 2, '2026-04-10 10:09:00', '2026-04-10 10:49:28', NULL);
