(1, 'Sahne Medya', 'info@sahnemedya.com', NULL, '05442621505', NULL, 'Reşatbey, Berk Apt. 62017 Sk. No: 1 Kat: 2 Daire: 2', 'Türkiye', 'ADANA', 'Seyhan', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-04-08 07:58:38', '2026-04-08 07:58:38', NULL);
INSERT INTO `features` (`id`, `page_id`, `name`, `gun`, `image`, `content`, `url`, `hit`, `published`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 92, 'Ulu Camii test', NULL, 'ulu-camii-test-e2yv.jpg', '<p>Cami-i Nur adıyla anılan ve bulunduğu semte de Cami-Nur ismini veren bu cami, Tarsus merkezinde yer alan Türk-İslam sanatının önde gelen eseridir. 1579 yılında Ramazanoğulları\'ndan Piri Paşanın oğlu İbrahim Bey tarafından yaptırılmıştır. Selçuk-Osmanlı üslubunda tek şerefeli minaresi olan camii yapımında tümüyle kesme taş kullanılmıştır. Avlu taş levhalarla kaplı olup ortada (H.1323) tarihli onarım kitabesi bulunan bir şadırvanı mevcuttur.</p>', 'https://maps.app.goo.gl/K4zDc1W7XGpJ7mHx5', 10, 1, '2026-04-09 11:16:53', '2026-04-09 12:54:31', NULL),
(2, 92, 'Tarsus Taşkuyu Mağarası', NULL, 'tarsus-taskuyu-magarasi-c4n7.jpg', '<p>Taşkuyu Mağarası, Tarsus\'un yaklaşık 10 km kuzeybatısında bulunuyor. Mağara, Permo-Karbonifer yaşlı mermerler ile bunları örten Miyosen yaşlı kireçtaşları dokanağında gelişmiştir. Mağaranın girişi deniz seviyesinden 214 metre yükseklikte ve bilinen toplam uzunluğu 470 metredir. Yüzeye son derece yakın bulunan mağarada sıcaklık 19.5 – 24 derece arasında ve nisbi nem yüzde 77 ile 89 arasındadır. Mağara birbirine bağlı galerilerden oluşmaktadır. Bu galerilerde sarkıt, dikit, sütun, duvar ve perde damla taşları, örtü damla taşları ve havuzların etkileyici örneklerini görmek mümkündür.</p>', 'https://maps.app.goo.gl/AMYL6LLZ9W4qfEjy5', 20, 1, '2026-04-09 11:16:53', '2026-04-09 12:53:53', NULL),
(3, 93, 'Yılankale', NULL, 'yilankale-4ych.jpg', '<p>Ceyhan’a 13 kilometre uzaklıktaki Yılankale\'nin, Bizanslılar zamanında yaptırıldığı varsayılır. Ceyhan Ovası’na tamamen hâkim, çok sarp bir tepe üzerine kurulmuştur. Eski adı Govara (Kovara) olan kaleye, yörede Şahmeran efsanesinin geçtiği yer olarak kabul edilmesinden dolayı, ünlü Türk gezgini Evliya Çelebi 17\'nci yüzyılda Şahmeran Kalesi adını vermiştir.</p>', 'https://maps.app.goo.gl/kmndd8nSZaodEWeZA', 10, 1, '2026-04-09 11:39:18', '2026-04-09 12:54:19', NULL),
(4, 92, 'Tarsus Şelalesi', NULL, 'tarsus-selalesi-reon.jpg', '<p>Akdeniz\'e dökülmeden önce Tarsus Ovası\'nda geniş yaylar çizen Berdan, (antik Kydnos) aynı zamanda Tarsus\'un kurulmasında önemli tercih sebebidir. Soğuk su anlamına gelen Berdan, aynı zamanda kentin 4 km. kuzeyinde doğal bir güzelliği de barındırmaktadır. Bizans İmparatoru Justinyen (M.S. 527-565) tarafından yatağı değiştirilirken, aslında Roma Dönemi sonlarına dek kullanılmış nekropol alanında geniş ve yüksek bir çağlayana dönüşmüştür. Kenti su taşkınlarından korumak için yapılan bu çalışma sonunda bugün yaklaşık 15 m. yükseklikteki konglomera kayalıklardan dökülen su, özellikle kış ve bahar aylarında karların erimesiyle en yoğun debisine ulaşmaktadır.</p>', 'https://maps.app.goo.gl/9VTAAsA5var3TjmV6', 30, 1, '2026-04-09 12:11:08', '2026-04-09 12:11:08', NULL),
(5, 92, 'Tarsus Müzesi', NULL, 'tarsus-muzesi-4cwb.jpg', '<p>Tarsus, 7 bin 500 yıllık kesintisiz bir kültür dokusuna sahiptir. İlçenin tarihi ve kültürel değerlerini yerli ve yabancı ziyaretçilere sunabilmek amacıyla Tarsus Müzesi, 1970 yılında Tarihi Kubatpaşa Medresesi’nde hizmete açıldı. Birkaç yer değişten Tarsus Müzesi son olarak Aralık 2020 yılında eski Adliye Binasına taşındı. Müzede, Çukurova kültürünün önemli bir parçası olan Tarsus ve yöresine ait eserler sergileniyor. Müzede ayrıca bir de Tarsus evi Köşesi oluşturularak geçmiş ev kültürü günümüze yansıtılmıştır. Günlük hayatın geçtiği evde kadının yeri ve dünyası ile sofra kültürü canlandırılmıştır.</p>', 'https://maps.app.goo.gl/5Uek76aFtQM9TFTo6', 40, 1, '2026-04-09 12:53:37', '2026-04-09 12:53:37', NULL);
