INSERT INTO `pages` (`id`, `hit`, `sezon_id`, `title`, `inside_title`, `slug`, `link`, `link2`, `link3`, `heyzen`, `content`, `location`, `video`, `youtubeplaylist`, `ses`, `spotify`, `image`, `icon`, `file`, `is_main`, `blade_id`, `category_id`, `translation_of`, `parent_page`, `lang_id`, `form_active`, `published`, `show_menu`, `show_homepage`, `show_footer`, `show_sponsorluk`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 2, NULL, 'Portakal Çiçeği Karnavalı Hakkında', NULL, 'portakal-cicegi-karnavali-hakkinda', NULL, NULL, NULL, NULL, '<p>Nisan ayının en güzel olduğu şehirlerden biridir, Adana…</p>\r\n\r\n<p>Tüm sokakları mis gibi portakal çiçeği kokar...</p>\r\n\r\n<p>Büyülüdür portakal çiçeği kokusu...</p>\r\n\r\n<p>Ruhunuz yıkanır,</p>\r\n\r\n<p>Gençleşirsiniz,</p>\r\n\r\n<p>Arınırsınız…</p>\r\n\r\n<p>Mesela, en küskün olduğu eski dostu affettirebilir insana ve tehlikelidir de biraz; insanı, yolda gördüğü ilk kişiye aşık edebilir.</p>\r\n\r\n<p>En güzel mevsimdir, Adana’da Nisan…&nbsp;<strong>Portakal Çiçeği&nbsp;&nbsp;</strong>mevsimi… Müthiş güzel bir iklime dönüşür. Ne soğuk, ne de sıcak… Hava, adeta “limonata” gibi olur.</p>\r\n\r\n<p>Kısa kollularınızı giyip çıkarsınız sokağa. Adana’nın sıcak, samimi insanlarıyla aynı sokaklarda yürürken, rüzgarın ara ara taşıyıp getirdiği o muhteşem portakal çiçeği kokusu, günün 24 saati bırakmaz peşinizi. Baygın bırakır insanı…</p>\r\n\r\n<p>Türkiye\'nin ya da dünyanın neresinde yaşarlarsa yaşasınlar, portakal çiçeği mevsiminde mutlaka Adana’ya gelir Adanalılar. Yılda sadece bir kez, en fazla 3-4 hafta sürecek bu coşkuyu kaçırmamak için…</p>\r\n\r\n<p>Portakal çiçeği mevsimi, iklim durumuna göre birkaç gün fark etmekle birlikte, genellikle Nisan ayı boyunca sürer. Bu site, bu müthiş deneyimi herkesin yaşayabilmesi için tanıtım amacıyla kurulmuştur.</p>\r\n\r\n<p>Önümüzdeki Nisan için şimdiden ajandanıza not alın lütfen. Özellikle de, portakal çiçeklerinin en yoğun olduğu Nisan ayında, bu unutulmaz deneyimi yaşayabilmeniz için hepinizi Adana’ya bekliyoruz.</p>', NULL, NULL, NULL, NULL, NULL, 'portakal-cicegi-karnavali-hakkinda-4lbv.png', NULL, NULL, 0, 1, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-03-31 09:17:08', '2026-04-30 11:53:45', NULL),
(2, 4, NULL, 'Ali Haydar Bozkurt Kimdir?', NULL, 'ali-haydar-bozkurt-kimdir', NULL, NULL, NULL, NULL, '<p>1967 yılında doğdum. Hayatımın ilk 29 yılını, Nisan’da sokakları portakal çiçeği kokan Adana’da yaşadım.</p>\r\n\r\n<p>Bu süre zarfında, eğitim hayatımın yanı sıra, profesyonel olarak tiyatro çalışmaları yaptım. Ayrıca uzun yıllar lisanslı basketbol oynadım. Fotoğrafçılık, müzik vb. hobilere de bir hayli zaman ayırdım.</p>\r\n\r\n<p>Düzenli olarak belirli aralıklarla mutlaka Adana’yı ziyaret etmeye devam ediyorum.</p>\r\n\r\n<p>Ancak, özellikle de her yıl Nisan’da, yani biz Adana sevdalılarının deyimiyle Portakal Çiçeği Mevsimi’nde, dünyanın neresinde olursam olayım mutlaka Adana’ya gelmeye devam ediyorum. Sadece 1 yıl yapamamıştım bunu. O yıl da sağ olsunlar, öğretmenim, sevdiğim dostlarım topladıkları portakal çiçeklerini kavanozlara koyup kargo ile bana göndermişlerdi. Bir hafta o kavanozları saklamıştım buzdolabımda. Her gün sabah akşam kavanozları açıp kokluyor, gözlerimi kapatıp Nisan’da Adana sokaklarında dolaştığımı hayal ediyordum. Bunu daha önce yaşamamış bir insana anlatmak biraz zordur belki. Ama bir kez yaşayanın ömür boyu aklında kalacak bir güzelliktir.</p>\r\n\r\n<p>Her Nisan’da mutlaka Adana’ya gidiyor, özellikle de portakal çiçeklerinin en yoğun koktuğu akşamüzeri saatlerinde kot pantolonumu, tişörtümü ve olmazsa olmaz beyaz Converse’lerimi giyip şehrin caddelerine çıkıyorum. Saatlerce yapmaktan yorulmadığım, bıkmadığım bir şey bu yürüyüşler… Geçtiğim her yerde farklı bir anı... Fonda dalga dalga o müthiş portakal çiçeği kokuları… Herkesi ve her şeyi sevdirebilecek kadar ruhumu yıkayan o büyülü koku…</p>\r\n\r\n<p>Biz çocukken Adana’da şehir merkezine çok yakın portakal bahçeleri de vardı ve akşamüzeri oldu mu, rüzgar o bahçelerden topladığı portakal çiçeği kokularını şehrin sokaklarına taşırdı. Geçtiği her yerde dalga dalga çarpardı yüzümüze… Şimdi, şehir merkezindeki portakal bahçeleri yok belki ama tüm sokaklardaki portakal (turunç) ağaçları ve şehir merkezindeki parklardaki ağaçlar sayesinde, yürüdüğünüz tüm caddelerde aynı kokuyu bulabilirsiniz.</p>\r\n\r\n<p><strong>Adana’da sosyal, sanatsal ve spor ağırlıklı bir eğitim hayatım oldu. Ayas Koleji mezunuyum. Hatta okulun ilk erkek mezunlarındanım. Sınıfta sadece 2 erkek okumuştuk. Tek sorunumuz, sınıflararası basketbol maçlarında erkek takımı kuramadığımız için kız-erkek karışık takımlar kurmak zorunda oluşumuzdu. Şanslıydık… Ömür boyu anlatacağımız anılarımız, ömür boyu kopmayacağımız dostluklarımız olmuştu.</strong></p>\r\n\r\n<p>Üniversite yıllarında da Adana’dan kopmamış ve Çukurova Üniversitesi İngilizce İşletme Bölümü’nden mezun olmuştum.</p>\r\n\r\n<p>Tüm öğrenim hayatım boyunca hiç ders çalışmadım. Ders dışı zamanlarım tiyatro, basketbol, müzik, fotoğraf gibi uğraşlarla o kadar doluydu ki, ders çalışacak vaktim olmuyor, bu nedenle de dersleri, derste dinleyerek öğrenmeye çalışıyordum. Buna rağmen başarılı bir öğrenci oldum sanırım.</p>\r\n\r\n<p>1996 yılında (29 yaşındaydım o tarihte) biraz geç kalmış olmakla beraber, profesyonel çalışma hayatına başlamak için İstanbul\'a geldim.</p>\r\n\r\n<p>Bu süre zarfında farklı şirketlerde farklı görevlerde bulundum. Halen, Toyota Türkiye CEO\'su olarak görev yapıyorum. Bununla birlikte ALJ Mobilite Avrupa ve Türkiye CEO’su görevini de yürütmekteyim.</p>\r\n\r\n<p>Başarının “Fark yaratmaktan” geçtiğine, dünyadaki tüm iyiliklerin ve güzelliklerin gerçekleştirilmesi için en temel unsurun doğru iletişim olduğuna inanırım.</p>\r\n\r\n<p>Tüm bu sebeplerden Adana’ya özgü, fark yaratan güzellikleri sizlerle paylaşmak istedim. Bu sitenin kurulmasındaki en temel amaç, Adana’nın pek az bilinen portakal çiçeği mevsimini ve bu mevsimdeki güzellikleri olabildiğince çok kişiye anlatmaktır.</p>\r\n\r\n<p>Buradan hareketle, “Nisan’da Adana’da!” sloganı ile yola çıkmış bulunuyoruz. Adanalı olan, olmayan tüm dostların desteği ile bu harekâtı büyütüp, her Nisan daha fazla kişinin Adana’ya gitmesini, bu müthiş deneyimi yaşamasını sağlamak istiyoruz.</p>\r\n\r\n<p>Bu davet, hiçbir şekilde siyasi veya ticari bir amaç gütmemektedir. Bu konudaki hassasiyetimizi sonuna kadar koruyarak, sadece bir “sevgi” işi ortaya koymak ve bu güzelliği, Nisan’da Adana’da bizlerle yaşamak isteyen herkesi Adana’ya davet etmek istiyoruz.</p>\r\n\r\n<p>Normalde portakal çiçeği mevsimi her yıl iklim durumuna göre birkaç gün farklılık gösterebilmekle beraber, yaklaşık olarak 5-20 Nisan tarihleri arasına denk gelmektedir. Bu sebeple portakal çiçekleri kokusunun en yoğun olduğu Nisan\'ın ilk haftası bizlere eşlik etmenizi bekliyoruz. Elbette, sadece 1 günlük program yapmamanızı da tavsiye ederim. Bu sitenin içerisindeki ilgili bölümde, “Adana’da Neler Yapılır?” konusunda da sizlere detaylı bilgiler vermeye çalışacağım.</p>', NULL, NULL, NULL, NULL, NULL, 'ali-haydar-bozkurt-kimdir.png', NULL, NULL, 0, 1, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-03-31 09:25:02', '2026-04-30 11:54:03', NULL),
(3, 6, NULL, 'Geçmiş Seneler', NULL, 'gecmis-seneler', NULL, NULL, NULL, NULL, '<p>Türkiye’nin ilk ve tek sokak karnavalı özelliğini taşıyan Uluslararası Portakal Çiçeği Karnavalı, 2013 yılından bu yana yurt içinden ve yurt dışından binlerce katılımcıyı ağırlıyor. Rekorlara imza atan bu eşsiz etkinliğin verilerini sayfamızda bulabilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 12, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-03-31 09:27:39', '2026-04-30 11:54:13', NULL),
(5, 24, NULL, '2024 Yılında Portakal Çiçeği Karnavalı', NULL, '2024-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 09:37:30', '2026-03-31 09:37:30', NULL),
(6, 22, NULL, '2023 Yılında Portakal Çiçeği Karnavalı', NULL, '2023-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Türkiye\'de gerçekleşen 6-7 Şubat 2023 Kahramanmaraş merkezli depremler ve depremin hemen ardından yaşanan sel felaketi nedeniyle festival komitesi, Kültür Turizm Bakanlığı, Adana Valiliği ve Adana Büyükşehir Belediyesi’nin ortak kararıyla iptal edildi. Ülkemizi derin yasa boğan ve Adana’da da çok sayıda can kaybının olduğu bu büyük depremde kaybettiğimiz vatandaşlarımız için tüm ulusumuza başsağlığı diliyoruz.</p>', NULL, NULL, NULL, NULL, NULL, '2023-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 09:42:19', '2026-03-31 09:42:20', NULL),
(7, 20, NULL, '2022 Yılında Portakal Çiçeği Karnavalı', NULL, '2022-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Karnaval, onuncu yılında 23-27 Mart 2022 tarihleri arasında gerçekleşti. Yurt içinden ve yurt dışından bölgeye gelen yaklaşık 300 bin karnaval gezgininin kişi başı ortalama harcamasının 500 TL olduğu tahmin ediliyor. Konaklama, yeme-içme, eğlence, alışveriş ve benzer harcamalar da hesaba katıldığında Adana dışından gelecek olanların Adana ekonomisine katkısının yaklaşık 150 milyon TL dolayında olduğunu söyleyebiliriz. Ayrıca, etkinliklere Adana’dan katılacak yaklaşık 1 milyon kişinin karnaval boyunca yapacağı yeme-içme, eğlence, alışveriş gibi kalemlere kişi başı ortalama 200 TL gibi sembolik bir harcama yaptığı hesaba katılınca, 200 milyon TL civarında da bir iç ticaret hacmi ortaya çıktığı görülüyor. Tüm bu sayılara şehirler arası hava ve kara ulaşımı, şehir içi özel ve toplu taşıma gibi diğer bazı harcamalar eklendiğinde, yaklaşık 350 milyon TL’lik Portakal Çiçeği Karnavalı ekonomisi oluştuğu raporlanmıştır.</p>', NULL, NULL, NULL, NULL, NULL, '2022-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 09:50:32', '2026-03-31 09:50:32', NULL),
(8, 18, NULL, '2021 Yılında Portakal Çiçeği Karnavalı', NULL, '2021-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Covid-19 pandemisinin devam etmesinden dolayı, 1-4 Nisan 2021 tarihleri arasında hem çevrim içi ortamda canlı olarak hem de kısıtlı sayıda katılımcının arabalarının içinde katıldığı bir hibrit karnaval gerçekleşti.</p>', NULL, NULL, NULL, NULL, NULL, '2021-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 09:52:50', '2026-03-31 09:52:50', NULL),
(9, 16, NULL, '2020 Yılında Portakal Çiçeği Karnavalı', NULL, '2020-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>2020 yılında bütün dünyayı etkisi altına alan Covid-19 pandemisi nedeniyle karnaval iptal edildi. Çevrim içi ortamda gerçekleştirilen karnavala birçok ünlü isim destek verdi.</p>', NULL, NULL, NULL, NULL, NULL, '2020-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 09:55:00', '2026-03-31 09:55:00', NULL),
(10, 14, NULL, '2019 Yılında Portakal Çiçeği Karnavalı', NULL, '2019-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Karnaval, yedinci yılında 3-7 Nisan 2019 tarihleri arasında gerçekleşti. Adana&nbsp; ve içinde bulunduğu bölge için önemli bir ekonomik etki yaratan Portakal Çiçeği Karnavalında, kentteki tüm otel ve restoranların, yeme, içme ve eğlence noktalarının, mağazaların, karnavalda stant açan yüzlerce küçük girişimcinin, marketlerin, toptancı ve dağıtımcıların, gıda üreticilerinin ve hatta taksicilerin gelirlerinde bile ciddi artışlar oldu. Karnaval ile iç turizmin canlanması, Adana ekonomisinin hemen her sektöründe bir tür domino etkisi yarattı. Karnavalın Adana’da ve çevre şehirlerde toplamda 150 milyon TL’lik bir dönemsel ekonomik hareket yarattığı da raporlandı.</p>', NULL, NULL, NULL, NULL, NULL, '2019-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:01:51', '2026-03-31 10:01:52', NULL),
(12, 12, NULL, '2018 Yılında Portakal Çiçeği Karnavalı', NULL, '2018-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Türkiye\'nin ilk ve tek sokak karnavalında, her yıl olduğu gibi bu yıl da 1,5 milyon kişi Adana sokaklarını büyük bir şölen alanına çevirdiler. Karnavalda düzenlenen etkinliklere katılanlar büyük coşkuya ortak olurken, rengarenk giysileriyle sokak ve caddeleri dolduran Adanalılar hafta sonu boyunca adeta uyumadılar.</p>', NULL, NULL, NULL, NULL, NULL, '2018-yilinda-portakal-cicegi-karnavali.png', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:08:50', '2026-03-31 10:08:50', NULL),
(13, NULL, NULL, 'Sürdürülebilirlik', NULL, 'surdurulebilirlik', NULL, NULL, NULL, NULL, '<p>Uluslararası Portakal Çiçeği Karnavalı kültürel bir eğlence etkinliği olmanın ötesinde, ekonomik, sosyal ve çevresel etkileriyle bir sürdürülebilirlik vizyonuna sahiptir.</p>\r\n\r\n<p>Pek çok yönüyle 17 Birleşmiş Milletler Sürdürülebilir Kalkınma Amacının 9 tanesine ve bu amaçların alt hedeflerine doğrudan hizmet eder.</p>', NULL, NULL, NULL, NULL, NULL, 'surdurulebilirlik-o6kb.jpg', 'surdurulebilirlik-icon-nyxl.jpg', NULL, 1, 9, 5, NULL, NULL, 1, 0, 1, 0, 1, 0, 0, '2026-03-31 10:09:15', '2026-04-30 11:49:35', NULL),
(14, 10, NULL, '2017 Yılında Portakal Çiçeği Karnavalı', NULL, '2017-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Dünyanın sayılı karnavalları arasına girmeyi başaran “Uluslararası Portakal Çiçeği Karnavalı’nda” eğlenceli etkinliklerin yanında çok sayıda kültürel ve sanatsal aktivite de yer aldı. Baharı müjdeleyen portakal çiçekleri kokularının eşliğinde, büyük coşkuyu yaşamak isteyen 100 bini Adana dışından olmak üzere yaklaşık; 1,5 milyon kişi Adana sokaklarında buluştu.</p>', NULL, NULL, NULL, NULL, NULL, '2017-yilinda-portakal-cicegi-karnavali.png', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:09:47', '2026-03-31 10:09:47', NULL),
(15, 8, NULL, '2016 Yılında Portakal Çiçeği Karnavalı', NULL, '2016-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Karnaval için Adana ve çevresine yatılı gelenlerin 20-25 bin kişi, şehir dışından günübirlik gelenlerin sayısının ise 75-80 bin civarında olduğu tahmin ediliyor. 2012 yılında 114 bin 266’sı yabancı, 429 bin 799’u yerli olmak üzere Adana’da konaklayan toplam turist sayısı 544 bin 65 iken, bu sayı 2016 yılında 911 bine ulaştı.</p>', NULL, NULL, NULL, NULL, NULL, '2016-yilinda-portakal-cicegi-karnavali.png', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:10:49', '2026-03-31 10:10:49', NULL),
(16, 6, NULL, '2015 Yılında Portakal Çiçeği Karnavalı', NULL, '2015-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Otellerde yer bulunmuyor, ek uçak ve otobüs seferleri konuyor, çadırlar için kamp alanları kuruluyor… Bu yıl karnaval rekorlara sahne oldu. Resmi verilere göre 90 bin kişi katıldı ve açılış töreni ile konsere katılım 150 bine ulaştı. Düzenlenen etkinlikleri yerinde izleyenlerin sayısının 350 bin civarında olduğu karnaval, böylelikle Türkiye\'de yaşayan hemen herkesin bildiği büyük bir organizasyona dönüştü.</p>', NULL, NULL, NULL, NULL, NULL, '2015-yilinda-portakal-cicegi-karnavali.png', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:12:04', '2026-03-31 10:12:04', NULL),
(17, 4, NULL, '2014 Yılında Portakal Çiçeği Karnavalı', NULL, '2014-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Düzenlendiği ilk yıl olan 2013 yılında 100 bin, 2014 yılında ise 140 bin kişi karnaval etkinliklerini yerinde izledi. 2013 yılında Adana’dan ve Adana dışından yaklaşık 15 bin kişinin, 2014 yılında da 30 bin kişinin coşkuyla katıldığı kortej ile karnaval etkinlikleri büyük bir ilgi ile karşılandı.</p>', NULL, NULL, NULL, NULL, NULL, '2014-yilinda-portakal-cicegi-karnavali.png', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:13:57', '2026-03-31 10:13:57', NULL),
(18, 2, NULL, '2013 Yılında Portakal Çiçeği Karnavalı', NULL, '2013-yilinda-portakal-cicegi-karnavali', NULL, NULL, NULL, NULL, '<p>Karnaval ilk olarak 12-14 Nisan 2013’te gerçekleşti. 100 bin katılımcıya ulaşan 1. Uluslararası Portakal Çiçeği Karnavalı, 2013 yılında Adana’dan ve Adana dışından yaklaşık 15 bin kişinin katıldığı kortej ile açılışını yaptı.</p>', NULL, NULL, NULL, NULL, NULL, '2013-yilinda-portakal-cicegi-karnavali.jpg', NULL, NULL, 0, 1, 1, NULL, 3, 1, 0, 1, 0, 0, 0, 0, '2026-03-31 10:14:56', '2026-03-31 10:14:56', NULL),
(19, 8, NULL, 'Fotoğraf Arşivi', NULL, 'fotograf-arsivi', NULL, NULL, NULL, NULL, '<p>Her yıl nisan ayında Adana’nın Cadde ve sokaklarını rengârenk giysileriyle bir şölene dönüştüren Uluslararası Portakal Çiçeği Karnavalı’na ilişkin görselleri sayfamızda inceleyebilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 13, 1, NULL, NULL, 1, 0, 1, 1, 1, 0, 0, '2026-03-31 10:26:34', '2026-04-30 11:54:21', NULL),
