(34, 10, NULL, 'Video Arşivi', NULL, 'video-arsivi', NULL, NULL, NULL, NULL, '<p>Türkiye’nin en değerli markalarından biri olan Uluslararası Portakal Çiçeği Karnavalı’na ait tanıtım, haber ve etkinlik videolarını izlemek için sayfamızı ziyaret edebilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 15, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-04-02 04:54:40', '2026-04-30 11:54:27', NULL),
(35, 2, NULL, 'Karnaval Şarkıları', NULL, 'karnaval-sarkilari', NULL, NULL, NULL, NULL, '<p>Güncelleniyor...</p>', NULL, 'PLVlRjYtTtJ_xuBoFKWE-Bc0p3U2967y_m', NULL, NULL, NULL, 'karnaval-sarkilari.jpg', NULL, NULL, 0, 16, 1, NULL, 34, 1, 0, 1, 0, 0, 0, 0, '2026-04-02 05:00:11', '2026-04-19 11:56:55', NULL),
(36, 4, NULL, 'Haber Videoları', NULL, 'haber-videolari', NULL, NULL, NULL, NULL, '<p>Güncelleniyor...</p>', NULL, 'PLVlRjYtTtJ_y0Zh5ktwdNj7r7tJJ4s-83', NULL, NULL, NULL, 'haber-videolari.jpg', NULL, NULL, 0, 16, 1, NULL, 34, 1, 0, 1, 0, 0, 0, 0, '2026-04-02 05:04:52', '2026-04-19 11:55:48', NULL),
(37, 6, NULL, 'Tanıtım Filmleri', NULL, 'tanitim-filmleri', NULL, NULL, NULL, NULL, '<p>Uluslararası Portakal Çiçeği Karnavalı’nın, her yaştan milyonları Adana sokaklarında buluşturan renkli etkinliklerini içeren tanıtım filmlerini sayfamızda izleyebilirsiniz.</p>', NULL, 'PLVlRjYtTtJ_yighlqmuEiPB6b6tTPNWkO', NULL, NULL, NULL, 'tanitim-filmleri.jpg', NULL, NULL, 0, 16, 1, NULL, 34, 1, 0, 1, 0, 0, 0, 0, '2026-04-02 05:11:34', '2026-04-19 11:46:57', NULL),
(55, 14, NULL, 'Karnaval Şarkısı', NULL, 'karnaval-sarkisi', NULL, NULL, NULL, NULL, '<p>Söz ve müziği Ezgi Özbay’a, düzenlemesi Suat Aydoğan’a ait \"Nisan’da Adana’da Dökülün Sokaklara\" şarkısıyla karnaval coşkusuna siz de ortak olabilirsiniz.</p>\n\n<p>Nisan’da Adana’da Dökülün Sokaklara</p>\n\n<p>Dökülün sokaklara ıslık çalmaya,</p>\n\n<p>Bu karnaval şarkısına ortak olmaya,</p>\n\n<p>Hep birlikte söyleyelim gönüller coşsun,</p>\n\n<p>Portakal çiçeğini tüm Türkiye duysun,</p>\n\n<p>NİSAN’DA ADANA’DA,</p>\n\n<p>COŞALIM KARNAVALDA,</p>\n\n<p>ÇALALIM GÜMBÜR GÜMBÜR,</p>\n\n<p>HAYDİ ŞİMDİ ISLIKLA.</p>\n\n<p><strong>Söz-Beste: Ezgi Özbay</strong></p>\n\n<p><strong>Düzenleme: Suat Aydoğan</strong></p>', NULL, NULL, NULL, 'karnaval-sarkisi-ses-zdr1.mp3', NULL, 'karnaval-sarkisi.jpg', NULL, NULL, 0, 1, 1, NULL, NULL, 1, 0, 1, 1, 1, 0, 0, '2026-04-02 06:45:40', '2026-04-30 11:54:45', NULL),
(56, 16, NULL, 'Karnaval Tanıtım Filmi', NULL, 'karnaval-tanitim-filmi', NULL, NULL, NULL, NULL, '<p>2025 yılı Uluslararası Portakal Çiçeği Karnavalı’nın coşku ve heyecan dolu, birbirinden renkli etkinliklerini tanıtan video içeriğini sayfamızda izleyebilirsiniz.</p>\r\n\r\n<p>2025 KARNAVAL TANITIM VİDEOSU</p>', NULL, 'https://www.youtube.com/embed/akYLKCKhpjI?si=1tv8ZJx-tVD9MdrN', NULL, NULL, NULL, NULL, NULL, NULL, 0, 31, 1, NULL, NULL, 1, 0, 1, 0, 0, 0, 0, '2026-04-02 06:48:44', '2026-04-27 14:02:30', NULL),
(57, 18, NULL, 'Basın Odası', NULL, 'basin-odasi', NULL, NULL, NULL, NULL, '<p>Etkinlik süresince, birbirinden renkli aktiviteleriyle yerel ve ulusal basın tarafından yakından takip edilen karnavala dair yazılı ve görsel haberleri sayfamızda inceleyebilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 19, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-04-02 06:55:05', '2026-04-30 11:54:49', NULL),
(58, NULL, NULL, 'Görsel Basında Karnaval', NULL, 'gorsel-basinda-karnaval', NULL, NULL, NULL, NULL, '<p>Ünü ülke sınırlarını aşan Uluslararası Portakal Çiçeği Karnavalı’nın yerel ve ulusal televizyonlarda yayımlanan haberlerine sayfamızdan ulaşabilirsiniz.</p>', NULL, 'PLVlRjYtTtJ_y0Zh5ktwdNj7r7tJJ4s-83', NULL, NULL, NULL, 'gorsel-basinda-karnaval.jpg', NULL, NULL, 0, 16, 1, NULL, 57, 1, 0, 1, 0, 0, 0, 0, '2026-04-02 06:57:40', '2026-04-19 13:10:13', NULL),
(59, 20, NULL, 'Sıkça Sorulan Sorular', NULL, 'sikca-sorulan-sorular', NULL, NULL, NULL, NULL, '<p>Ülkenin önde gelen kültür-sanat organizasyonlarından biri olan Portakal Çiçeği Karnavalı, binlerce yerli ve yabancı turistin ilgisini çekiyor. Ünü ülke sınırlarını aşan organizasyonla ilgili merak edilen soruların yanıtlarına sayfamızdan ulaşabilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 1, 1, NULL, NULL, 1, 0, 1, 1, 1, 0, 0, '2026-04-02 06:59:47', '2026-04-30 11:54:54', NULL),
(60, 22, NULL, 'Karnaval Programı', NULL, 'karnaval-programi', NULL, NULL, NULL, 'https://heyzine.com/flip-book/62ffb1f418.html', '<p>2026 Uluslararası Portakal Çiçeği Karnavalı program akışını aşağıda inceleyebilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'karnaval-programi-file-sccj.pdf', 0, 1, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-04-02 07:08:14', '2026-04-30 11:54:59', NULL),
(63, 6, NULL, '2015 Karnaval Programı', NULL, '2015-karnaval-programi', NULL, NULL, NULL, NULL, '<p>2015 Uluslararası Portakal Çiçeği Karnavalı program akışını aşağıda inceleyebilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 1, 1, NULL, 60, 1, 0, 1, 0, 0, 0, 0, '2026-04-02 07:56:46', '2026-04-19 13:37:49', '2026-04-19 13:37:49'),
(74, 24, NULL, 'Sponsorlarımız', NULL, 'sponsorlarimiz', NULL, NULL, NULL, NULL, '<p>Adana’nın parlayan markaları arasında yer alan Uluslararası Portakal Çiçeği Karnavalı, güçlü sponsorlarının desteğiyle daha görkemli etkinliklere ev sahipliği yapıyor. Karnavala değer katan sponsorlarımızı sayfamızda keşfedebilirsiniz.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 20, 1, NULL, NULL, 1, 0, 1, 1, 0, 0, 0, '2026-04-02 09:08:15', '2026-04-30 11:55:03', NULL),
